arg:thesis_1 a arg:Thesis ;
    arg:hasText "Censorship in libraries is stupid because exposure to explicit material is inevitable" .

arg:claim_2 a arg:SubClaim ;
    arg:hasText "Libraries possess books, magazines, and music containing explicit material that is unavoidable in the modern world" ;
    arg:supports arg:thesis_1 .

arg:counter_3 a arg:Counter ;
    arg:hasText "Some material can and should be in separate areas from mainstream material" ;
    arg:counters arg:thesis_1 .

arg:rebuttal_4 a arg:Rebuttal ;
    arg:hasText "On the whole, who cares? Most ordinary people do not care about explicit material in libraries" ;
    arg:rebuts arg:counter_3 .

arg:claim_5 a arg:SubClaim ;
    arg:hasText "If you have not heard of explicit content yet, you will soon regardless of censorship steps taken" ;
    arg:supports arg:thesis_1 .

