arg:thesis_1 a arg:Thesis ;
    arg:hasText "The builders of the Empire State Building faced many obstacles in attempting to allow dirigibles to dock there" .

arg:claim_2 a arg:SubClaim ;
    arg:hasText "The building needed to be strengthened to support a thousand-foot dirigible moored at the top" ;
    arg:supports arg:thesis_1 .

arg:evidence_3 a arg:QuantifiedEvidence ;
    arg:hasText "MONEY1 worth of changes had to be made to the building framework" ;
    arg:supports arg:claim_2 .

arg:claim_4 a arg:SubClaim ;
    arg:hasText "Wind pressure from a moored dirigible had to be transmitted all the way to the building foundation" ;
    arg:supports arg:thesis_1 .

arg:evidence_5 a arg:Evidence ;
    arg:hasText "This was solved by making changes to the skeleton of the building, though the solution was uncertain" ;
    arg:supports arg:claim_4 .

arg:claim_6 a arg:SubClaim ;
    arg:hasText "The building needed space to provide for passengers arriving from the blimps" ;
    arg:supports arg:thesis_1 .

arg:evidence_7 a arg:Evidence ;
    arg:hasText "They built a shaft to bring passengers down to the 86th floor where baggage and ticket areas would be located" ;
    arg:supports arg:claim_6 .

arg:structural_8 a arg:Structural ;
    arg:hasText "Three-part parallel structure: each obstacle presented with its solution" ;
    arg:contains arg:claim_2 ;
    arg:contains arg:claim_4 ;
    arg:contains arg:claim_6 .
